INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'MTD 74', 'メロディウィーク', 'GPS電波受信機能なし. 活気の出るメロディと「おはようございます」のアナウンスの2曲で業務スタート。お好きな曲やアナウンスをSDカード(別売)で簡単に追加可能。2曲連続再生も可能。外部ベルとの接続でお知らせ。マイク放送が可能。無電圧接点を出力できる機器に連動して報知が可能。', 119000, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTD%2074', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', 280, 410, 60);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'MTDGP 74', 'メロディウィーク GPS受信機能付', 'GPS電波受信機能付. 活気の出るメロディと「おはようございます」のアナウンスの2曲で業務スタート。お好きな曲やアナウンスをSDカード(別売)で簡単に追加可能。2曲連続再生も可能。外部ベルとの接続でお知らせ。マイク放送が可能。無電圧接点を出力できる機器に連動して報知が可能。GPS受信ユニットを設置することにより正確な時間にチャイムでお知らせ。', 176000, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTDGP%2074', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', 280, 410, 60);
