INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'null', '多回路 エネルギーモニタ', '本体ユニット1台で最大4回路までの電圧、電流、電力、力率などを計測。さらにユニットを増設すれば最大16回路(単相2線なら32回路)まで系統別に対応できる本格タイプの計測器です。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=null', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'MBT3740K', 'エネミエール S (通信機能付)', '初期導入におすすめの1回路計測タイプ。エネルギー使用量を自動計測し、はかったその場で「見える化」。エネルギー管理の運用をサポートする便利機能を多数搭載しています。', 72700, 'https://dummyimage.com/200x200/cccccc/000.png&text=MBT3740K', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', 110, 150, 49);
