INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'IPD', 'CJ SERIES MULTI-FUNCTION HAND GRIP CONTROL', '高いレベルの安全性が求められるアプリケーションに最適。多用途に使用可能な人間工学的デザイン。簡単取付け&簡単操作。IP67、ホール素子を採用し高い信頼性を実現。アナログ、CANbus、デジタルUSB出力。2.3軸から選択可能。多用途に使用可能な人間工学的ハンドル。機械的寿命: 300万回。テクノロジー: ホール効果。軸数: 最大3軸。出力オプション: あり。USB: あり。パネル前面保護構造: あり。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 71);
