INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'RS', 'CJ SERIES MULTI-FUNCTION HAND GRIP CONTROL', '高いレベルの安全性が求められるアプリケーションに最適。多用途に使用可能な人間工学的デザイン。簡単取付け&簡単操作。IP67、ホール素子を採用し高い信頼性を実現。アナログ、CANbus、デジタルUSB出力。2.3軸から選択可能。多用途に使用可能な人間工学的ハンドル。機械的寿命: 300万回。テクノロジー: ホール効果。軸数: 最大3軸。出力オプション: あり。USB: あり。パネル前面保護構造: あり。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 71);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), '600H-600NHシリーズ', '高電流トグルスイッチ', '特長: 堅牢構造、高電流・高電圧タイプ、メタルレバー(600H)・絶縁レバー(600NH)、UL、CSA、NF及びVDE認証。電気的仕様: 最大電圧/電流定格は下表参照。初期接触抵抗: 10mΩ max.。絶縁抵抗: 1,000 MΩ min. (DC500Vメガにて)。耐電圧: 端子間 AC2,000V、端子 - フレーム間 AC2,500V。電気的寿命は下表参照。材質: 本体はポリエステル樹脂。アクチュエータは600Hシリーズが黄銅ニッケルメッキ、600NHシリーズがポリアミド樹脂。ブッシングは黄銅ニッケルメッキ。接点は銀ニッケル。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 76);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'null', '押ボタンスイッチ ISシリーズ', '防水タイプ・φ13.6mm・モメンタリ形・NO。特長: 短胴(パネル奥行13mm)、小形・軽量タイプ、クリック感、保護構造IP67。性能仕様: パネル前面保護構造: IP67 (IEC 60529)。耐衝撃: 100G(IEC 60512-6-3、Test 6c)。耐振動: 10~500Hz - 10G(IEC 60512-6-4、Test 6d)。塩水噴霧試験: IEC 60512-11-6、Test 11f。使用・保存周囲温度: -40~+85°C。電気的仕様: 最大電圧/電流定格(抵抗負荷の場合): AC32V 0.4A DC48V 0.1A。初期接触抵抗: 100mΩmax.。絶縁抵抗: 1GΩ min(DC500Vメガにて)。耐電圧: AC1,000V。電気的寿命: 500,000回(AC32V 400mA)。回路構成: 1a(NO)。一般仕様: パネル厚: 1.5~4mm。ストローク: 1.7 mm ± 0.3 mm。操作力: 4N ±3 N。機械的寿命: 1,000,000回。ナット締付トルク: 1 N・m max. (金属ナットU166)。はんだ耐熱: 300°C max. 3秒以内。材質: 本体: 耐熱プラスチック。ボタン: ポリアミド樹脂。ブッシング・ベゼル: ポリアミド樹脂。接点: 銀に金接点。接点密封: エポキシ。認証マーク: AC125V/AC250V 2A File E83438。適用規格:UL1054。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, 13, undefined);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'IAシリーズ', '押ボタンスイッチ', '耐環境フラッシュシルエットタイプ・ø16mm・モメンタリ形。特長: 耐氷結・耐砂塵、クリック感、保護構造IP65 IP67。性能仕様: パネル前面保護構造:IP65 IP67 (IEC 60529)、塩水噴霧試験: IEC 60512-11-6、Test 11f、使用・保存周囲温度:-20~+65°C。電気的仕様: 最大電圧/電流定格(抵抗負荷の場合): DC24V 2A、初期接触抵抗: 100mΩ max.、絶縁抵抗: 100MΩ min(DC500Vメガにて)、耐電圧: AC500V、電気的寿命: 1,000,000回。一般仕様: パネル厚: 1~7mm max.、ストローク: 1.5mm ±0.3mm、操作力: 7N ±2N、機械的耐久性: 1,000,000回、ナット締付トルク: 0.5~1 N·m max.。取付方法: 取付穴加工: Ø16.2mm、最小取付ピッチ: 27 x 27mm(標準六角ナット付)。材質: 本体・ブッシング: 耐熱プラスチック、ボタン: ポリウレタン、接点: 銀に金接点、リード線: AWG20 (断面積0.6mm²)、端子密封: エポキシ。回路構成: 1a(NO), 1c(NC/NO)。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 90);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'null', '押ボタンスイッチ AVシリーズ', '特長: オルタネイト形, 照光タイプ, ドット照光, 保護構造IP65. 性能仕様: パネル前面保護構造: IP65 (IEC60529), 使用・保存周囲温度: -30~+70°C. 電気的仕様: 最大電圧/電流定格(抵抗負荷の場合): DC48V 2A, LED電圧・消費電流: 青 3.5V 10mA、緑 2V 10mA、赤 2V 20mA (抵抗は直列接続してください)(注), 初期接触抵抗: 100mΩ max., 絶縁抵抗: 1,000MΩ min (DC500Vメガにて), 耐電圧: 端子間 AC1,000V, 端子 - フレーム間 AC500V, 電気的寿命: 500,000回(DC48V2A). 一般仕様: 締付トルク: 5~14 N･m max., パネル厚: 1~9mm, 機械的寿命: 1,000,000回, はんだ耐熱: 300°C max.4秒以内. 取付方法: 取付穴加工: Ø22.2mm, 最小取付ピッチ: 30mm×30mm. 材質: 本体: ポリアミド樹脂, 接点: 銀, ブッシング: 形番構成をご覧ください。, ボタン: 形番構成をご覧ください。, 内部メンブレン: ネオプレン, 外部ガスケット: ネオプレン.', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 94);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'AVシリーズ', '押ボタンスイッチ', 'メタル形・ø22mm・モメンタリ形・NC/NO。特長: 大形ボタンタイプ、モメンタリNC/NO、ボタン表面処理:アルマイト、長寿命、保護構造IP65。性能仕様: 耐衝撃保護等級: IK08 (IEC62262、5J 〔ジュール〕)、パネル前面保護構造: IP65 (IEC60529)、使用・保存周囲温度: -20~+55°C。電気的仕様: 最大電圧/電流定格(抵抗負荷の場合): AC250V 5A、初期接触抵抗: 100mΩ max.、絶縁抵抗: 1,000MΩ min. (DC500Vメガにて)、耐電圧: 端子 - フレーム間 AC2,000V、電気的寿命: 1,000,000回(AC250V 1A)。一般仕様: 締付トルク: 5~14 N･m max.、パネル厚: 1~6mm、機械的寿命: 1,000,000回、はんだ耐熱: 300°C max. 5秒以内。取付方法: 取付穴加工: Ø22.2mm、最小取付ピッチ: 30mm×30mm。材質: コンタクト部:ポリエステル樹脂、接点:銀ニッケル、ブッシング:黄銅ニッケルメッキ、ボタン:アルミニウム (カラーアルマイト処理)、内部メンブレン:シリコン、外部ガスケット:ネオプレン。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 96);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'AVシリーズ', '押ボタンスイッチ AVシリーズ', '特長: モメンタリNO, 耐衝撃IK10, ステンレス製ボタン、ブッシング, 保護構造IP65. 性能仕様: 耐衝撃保護等級IK10, パネル前面保護構造IP65(IEC60529), 使用・保存周囲温度-30~+70°C. 電気的仕様: 最大電圧/電流定格(抵抗負荷の場合)DC12V 4A, 初期接触抵抗100mΩ max., 絶縁抵抗1,000MΩ min (DC500Vメガにて), 耐電圧(端子-フレーム間/端子間)AC2,000V, 電気的寿命500,000回(DC12V 4A). 一般仕様: ナット締付トルク5~14 N·m max., パネル厚1~11 mm, 機械的寿命1,000,000回, はんだ耐熱300°C max. 3秒以内. 材質: 本体PBT樹脂, 接点銀, ブッシングSUS303, ボタンSUS303, 内部メンブレンシリコン, 外部ガスケットネオプレン. 取付方法: 取付穴加工ø22.2mm, 最小取付ピッチ30mm×30mm.', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 98);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'AVシリーズ', '押ボタンスイッチ AVシリーズ メタル形・φ30mm・モメンタリ形・NC/NO', '特長: 大形堅牢ボタン, 照光リング, モメンタリNC/NO, リード線形, 保護構造IP67. 性能仕様: 耐衝撃保護等級: IK06(IEC62262、1J〔ジュール〕), パネル前面保護構造: IP67 (IEC60529), 使用・保存周囲温度: -30~+85°C. 電気的仕様: 最大電圧/電流定格(抵抗負荷の場合): DC30V 1A, LED電圧: DC24V, 初期接触抵抗: 100mΩ max., 絶縁抵抗: 10MΩ min (DC500Vメガにて), 耐電圧: 端子間 AC500V, 端子―フレーム間 AC1,000V, 電気的寿命: 250,000回(DC30V 1A). 一般仕様: ストローク: 2.5mm ±0.3 mm, 操作力: 5N ±2N, ナット締付トルク: 10N・m max., パネル厚: 1~6 mm, 機械的寿命: 1,000,000回, はんだ耐熱: 350°C max. 5秒以内. 材質: 本体: ポリアミド樹脂, 接点: 銀, ブッシング: SUS 316または黄銅ニッケルメッキ, ボタン: SUS 316, 黄銅ニッケルメッキ, 内部メンブレン: シリコン, 外部ガスケット: ニトリル. 取付方法: 取付穴加工: Ø30.2mm, 最小取付ピッチ: 44mm×44mm.', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 100);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'KG49A', 'パワーロッカースイッチ KGシリーズ', '特長: ガード付ロッカースイッチ, 非照光タイプ, 保護構造IP65. 性能仕様: パネル前面保護構造: IP65 (IEC60529), 耐衝撃: 100G(IEC 60512-6-3、Test 6c), 耐振動: 10~500 Hz/10G (IEC 60512-6-4、Test 6d), 塩水噴霧試験: 96時間(IEC60512-11-6、Test 11f), 使用・保存周囲温度: 2ポジションタイプ -40~+85°C, 3ポジションタイプ -10~+65°C. 電気的仕様: 電流/電圧定格(抵抗負荷の場合) 回路構成6(ON-ON): DC12V 15A、DC24V 10A max. DC14V 10mA min. 他の回路構成: DC12V 10A、DC24V 8A max. 初期接触抵抗: 100mΩ max. 絶縁抵抗: 1,000MΩ min. (DC500Vメガにて) 耐電圧: 端子間 AC2,000V, 電気的寿命: 10,000回. 一般仕様: 機械的寿命: 2ポジションタイプ 100,000回, 3ポジションタイプ 30,000回, 取付穴加工: 36.80×21.08mm, パネル厚: 0.8~4.6mm. 材質: 本体: 耐熱プラスチック, 端子: 黄銅銀メッキ, 接点: 銀, 接触ローラ: 黄銅ニッケルメッキ.', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 114);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'Q6シリーズ', 'LED表示灯 Q6シリーズ', 'Ø6mm。特長: ø3mmレンズ・高輝度LED表示灯、突形・フラッシュ形、リード線長200mm。環境仕様: IP67パネル前面保護構造(IEC 60529)、使用・保存周囲温度:-40~+85°C。性能仕様: 寿命: 50,000時間(25°C)、パネル厚:0.75~7mm。材質: ベゼル:黄銅、ブライトクロームまたは黒クローム仕上げ、本体: エポキシ樹脂。電気的仕様 (超高輝度タイプ): LED色と輝度 (突形/フラッシュ形/順電圧): 赤 (3,700 mcd/600 mcd/2.2 V), 緑 (2,000 mcd/350 mcd/3.2 V), 黄 (1,200 mcd/140 mcd/2.0 V), アンバー (4,500 mcd/400 mcd/2.2 V)。電圧と動作電流 (動作電圧 min~max/動作電流 Typ.): DC6V (DC5.4~6.6V/20 mA), DC12V (DC10.8~13.2V/20 mA), DC24V (DC21.6~26.4V/20 mA)。注記: 動作電圧は10%を超えないようにしてください。LED寿命が短くなる恐れがあります。電流値が下がると輝度は低下します。LED特性は使用環境により異なります。本チラシに記載された数値は参考であり、変動する可能性がありますのでご了承ください。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 138);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'Q8シリーズ', 'LED表示灯', 'ø8mm LED表示灯。特長: ø5mmレンズ高輝度LED、突形・フラッシュ形、リード線長200mm。環境仕様: IP67パネル前面保護構造(IEC 60529)、使用・保存周囲温度:-40~+85°C。性能仕様: 寿命50,000時間(25°C)、パネル厚0.75~7mm。材質: ベゼル(黄銅、ブライトクロームまたは黒クローム仕上げ)、本体(エポキシ樹脂)。電気的仕様(超高輝度タイプ): LED色(赤, 緑, 黄, アンバー)と電圧(DC6V, DC12V, DC24V, AC110V)の組み合わせで提供。各色の輝度、順電圧、動作電圧範囲、動作電流は表参照。動作電圧は10%を超えないようにしてください。LED寿命が短くなる恐れがあります。電流値が下がると輝度は低下します。LED特性は使用環境により異なります。記載数値は参考値です。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 140);
