INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'Q22シリーズ', 'LED表示灯', 'IDEC Q22シリーズ LED表示灯。取り付け穴径Ø22mm、LED径Ø16.75mmの高輝度タイプ。はんだ/ファストン端子形およびエポキシ樹脂リード線形(200mm)に対応。IP67パネル前面保護構造。使用・保存周囲温度は端子形-30~+65°C、リード線形-40~+85°C。寿命50,000時間(25°C)。対応パネル厚は突形1.75~12mm、フラッシュ形1.75~10mm、台形1~10mm。ベゼルは黄銅(ブライトクローム/黒クローム仕上げ)またはSUS 316L、本体はポリカーボネート樹脂またはSUS 316L。赤、緑、黄、青、白、RGBのLED色と、電流制限用抵抗非内蔵、DC12V、DC24V、AC110Vの電圧タイプが選択可能。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 150);
