INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'LWシリーズ', 'フラッシュシルエット®スイッチ', 'ベゼル高さ2㎜で衛生面や安全面にも貢献するスタイリッシュなスイッチ。集合密着取り付けが可能で、ロックレバー方式のセパレート構造により容易に着脱可能。鍵付セレクタスイッチはセキュリティ性の高いピンタンブラー構造を採用。保護構造はIP65(IEC60529)。ベゼルサイズはΦ28mm、パネル前面高さは2mm。形状は分離形。接点定格は3A。操作感はライト。操作ストロークは3mm。', NULL, NULL, 'https://drive.google.com/drive/folders/', 28, 28, NULL, 180);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'LSRD球', '新LED球', '業界初、ひとつで6色の役をこなすLED球。新しくなった照光ユニットは、これまで5色必要だったLED球をひとつのLED球で表現できるよう改良。急な照光色の変更があった場合でも、レンズのみの購入で色替えが可能。色変更・在庫管理の工数削減はもちろん環境にもやさしい製品。新LED球の採用により、従来より明るく鮮やかな色になりました。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 180);
