INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'HW-U10', 'コンタクトブロック (HW-U形)', '端子カバー不要のIP20構造。ワンタッチ結合用爪 (取付け、取外し用)。配線は2方向から可能。端子ねじ (M3.5)。橋絡片ホルダ。接点: 1a (NO)。端子番号: 3-4。ハウジングの色: 青。橋絡片ホルダの色: 緑。質量: 約11g。各ユニットへの取付けは、4接点 (2段) まで取付け可能です。指定により金接点対応可。(接点材質:銀に金接点)。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, undefined);
