INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'HW2B-M110*', 'HW2B-M1形 押ボタンスイッチ 角平形 モメンタリ形 1a接点', 'Ø22 HWシリーズ コントロールユニット 押ボタンスイッチ。ボタン色指定記号(*)により色選択可能(B:黒, G:緑, R:赤, Y:黄, S:青, W:白)。パネル厚: 0.8～6mm。端子ねじ: M3.5、端子カバー:一体形。接点構成が1接点および3接点のユニットにはダミーブロックが組み込まれます。1b接点の場合はコンタクトブロックの位置が左右入れ替わります。記載以外の接点構成および金接点ご指定に際しては B-184を、配線については B-227をご覧ください。', NULL, NULL, 'https://drive.google.com/drive/folders/', 29.4, 29.6, 49.4, undefined);
