INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'APW122D*', 'Ø22 TW パイロットライト 平形 APW1形', 'LED照光種別。定格使用電圧:AC/DC24V。色記号:R(赤)、G(緑)、Y(黄)、A(アンバー)、S(青)、PW (ピュアホワイト)に対応。LED球内蔵。感電防止用として、製品に端子カバーを付属しています。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 392);
