INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'OCW-10※', 'ボタンカバー (平形ボタン用)', 'ゴム製 (ニトリル系)。取付リングをゴムカバーで覆ったもので、押ボタンスイッチの防水性をより確実にします。ゴムカバー内にチップ (ボタン) を内蔵していますので、取付リングとスイッチ本体のチップを取り除いてからご使用ください。また、必ずチップ (ボタン) を本体の軸にかん合させてご使用ください。耐油性も良好です。※(色記号):B(黒)、G(緑)、R(赤)、Y(黄)。使用周囲温度:-5~+60℃。', NULL, NULL, 'https://drive.google.com/drive/folders/', 31, 18.5, 31, 409);
