INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'ASBN211N-A03*', 'IDEC Ø30 TWNシリーズ セレクタ押ボタンスイッチ リング操作形(90°2ノッチ)', 'IDEC Ø30 TWNシリーズ リング操作形(90°2ノッチ) ASBN2形セレクタ押ボタンスイッチ。販売単位:1個。リングは金属製クロームメッキ。ボタン色記号: B(黒)、G(緑)、R(赤)、Y(黄)。端子ねじ: M3.5、端子カバー一体形。パネル厚0.8～7.5mm。外形寸法: パネル面からの高さ41.4mm、本体直径35mm、パネル面からの奥行きは接点構成により45.4mm(1,2接点)または65.4mm(3,4接点)。セレクタ押ボタン操作時は、押ボタンを押した状態でリングを回転させないでください。動作種別Gは、リングが右のとき押ボタンは動作しません。動作種別E・Fは、ツマミを左右に選択すると左右のb接点がオーバーラップします。Fは押ボタンを押したときにa・b接点がオーバーラップすることがあります。このモデルは動作種別A03、接点構成1a-1b (11)、コンタクトブロックは1番がa接点、2番がb接点、リング位置は左がノーマル、右がプッシュ。ボタン色はBGRYから選択可能。☆印機種（接点使用電流が1/2）です。', NULL, NULL, 'https://drive.google.com/drive/folders/', 35, 41.4, 65.4, 442);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'ASBN211N-K04*', 'IDEC Ø30 TWNシリーズ セレクタ押ボタンスイッチ リング操作形(90°2ノッチ)', 'IDEC Ø30 TWNシリーズ リング操作形(90°2ノッチ) ASBN2形セレクタ押ボタンスイッチ。販売単位:1個。リングは金属製クロームメッキ。ボタン色記号: B(黒)、G(緑)、R(赤)、Y(黄)。端子ねじ: M3.5、端子カバー一体形。パネル厚0.8～7.5mm。外形寸法: パネル面からの高さ41.4mm、本体直径35mm、パネル面からの奥行きは接点構成により45.4mm(1,2接点)または65.4mm(3,4接点)。セレクタ押ボタン操作時は、押ボタンを押した状態でリングを回転させないでください。動作種別Gは、リングが右のとき押ボタンは動作しません。動作種別E・Fは、ツマミを左右に選択すると左右のb接点がオーバーラップします。Fは押ボタンを押したときにa・b接点がオーバーラップすることがあります。このモデルは動作種別K04、接点構成1a-1b (11)、コンタクトブロックは1番がb接点、2番がEM接点、リング位置は左がノーマル、右がプッシュ。ボタン色はBGRYから選択可能。☆印機種（接点使用電流が1/2）です。', NULL, NULL, 'https://drive.google.com/drive/folders/', 35, 41.4, 65.4, 442);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'ASBN211N-G03※', 'IDEC Ø30 TWNシリーズ セレクタ押ボタンスイッチ リング操作形(90°2ノッチ)', 'IDEC Ø30 TWNシリーズ リング操作形(90°2ノッチ) ASBN2形セレクタ押ボタンスイッチ。販売単位:1個。リングは金属製クロームメッキ。ボタン色記号: B(黒)、G(緑)、R(赤)、Y(黄)。端子ねじ: M3.5、端子カバー一体形。パネル厚0.8～7.5mm。外形寸法: パネル面からの高さ41.4mm、本体直径35mm、パネル面からの奥行きは接点構成により45.4mm(1,2接点)または65.4mm(3,4接点)。セレクタ押ボタン操作時は、押ボタンを押した状態でリングを回転させないでください。動作種別Gは、リングが右のとき押ボタンは動作しません。動作種別E・Fは、ツマミを左右に選択すると左右のb接点がオーバーラップします。Fは押ボタンを押したときにa・b接点がオーバーラップすることがあります。このモデルは動作種別G03、接点構成1a-1b (11)、コンタクトブロックは1番がa接点、2番がb接点、リング位置は左がノーマル、右が作動阻止。ボタン色はBGRYから選択可能。※印機種です。', NULL, NULL, 'https://drive.google.com/drive/folders/', 35, 41.4, 65.4, 442);
