INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'AVD310N*', 'Ø30 TWNDシリーズ 押ボタンスイッチ 大形 プッシュロックターンリセット形', '亜鉛ダイカスト製、Ø40ボタン。接点構成: 1a。ボタン色指定記号: B(黒), G(緑), R(赤), Y(黄)。プッシュロックターンリセット動作。国際安全規格ISO 13850、IEC 60947-5-5に基づく非常停止用スイッチとしては使用できません。丸リングはクロームメッキ。端子ねじ: M3.5、端子カバー:一体形。奥行きはパネル裏面寸法が接点数により45.4mm(1,2接点)または65.4mm(3,4接点)で変化します。', NULL, NULL, 'https://drive.google.com/drive/folders/', 40, 40, 94.8, 447);
