INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'ASBD211N-A03*', 'Ø30 TWNDシリーズ セレクタ押ボタンスイッチ', 'セレクタ押ボタンスイッチ(亜鉛ダイカスト製)。Ø30 TWNDシリーズ。リング操作形(90°2ノッチ)。接点構成:11(1a-1b)。コンタクトブロック:A03。リングは金属製クロームメッキ。ボタン色記号:B(黒)、G(緑)、R(赤)、Y(黄)。セレクタ押ボタンを操作するときは、押ボタンを押した状態でリングの回転操作は行わないでください。故障の原因になります。☆印の機種は、接点使用電流(負荷開閉電流値)が1/2になります。定格絶縁電圧および定格通電電流は同一値です。', NULL, NULL, 'https://drive.google.com/drive/folders/', 40, 29.4, 45.4, undefined);
