INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'OC-11B', '突形ボタン用 ボタンカバー (黒)', 'ゴム製 (ニトリル系) 取付リング (亜鉛ダイカスト製)。取付リングをゴムカバーで覆ったもので、押ボタンスイッチの防水性をより確実にします。ゴムカバー内にチップ (ボタン)は内蔵していません。突形押ボタンスイッチまたは突形チップに取り替えてご使用ください。耐油性にも良好です。使用周囲温度:-5~+60℃。', NULL, NULL, 'https://drive.google.com/drive/folders/', 38, NULL, 38, undefined);
