INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'HW1Z形', 'Ø22 照光/非照光ブザー', '音と光で注意喚起する防水仕様の照光ブザー。エレベータや生産現場の注意喚起に。省配線・省スペース。プッシュイン端子なので、電線を端子に軽く押し込むだけで簡単に配線できます。メンテナンス時の増し締めも必要ありません。IDECのHW1Z形ならパネル面のIP65対応で、装置のふき取りや洗浄が可能です。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 498);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'AP22形', 'Ø22 超高輝度LED表示灯', '用途に合わせて6色のカラーバリエーション（R, G, Y, A, S, PW）。明るい場所での点灯がより明確になるクリアレンズタイプも準備（PWを除く）。独自の光学設計でいろいろな方向から良く見える。取付方向を選ばず、設置場所が広がる。圧倒的な視認性で注意喚起用表示灯に最適。コンパクトタイプで狭くて小さい場所への設置が可能。配線工数の削減：端子カバーが一体構造のフィンガープロテクションタイプで、感電防止への安全を確保（IP20）。駅ホーム自動開閉安全柵では、遠方からの視認性も確保。CULUS LISTED, CE, UK CA 規格認証製品。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 508);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'AP6S形', 'Ø16小形表示灯', 'LED球小形表示灯でドーム形タイプ、高電圧(100V、200V)タイプの短胴形。屋外でもくっきり表示。保護構造 IP65 (IEC60529)。外付抵抗不要。整流・保護ダイオード内蔵。電流制限用抵抗および保護ダイオードは、LED球に内蔵しています。業界初! ひとつで6色の役をこなすLED球(LSRD球)を採用。新しくなった照光ユニットは、これまで5色必要だったLED球をひとつのLED球で表現できるよう改良しました。それにより、急な照光色の変更があった場合でも、レンズのみの購入で色替えが可能に。色変更・在庫管理の工数削減はもちろん環境にもやさしい製品ができました。新LED球(LSRD球)で視認性がアップ。対応色: 赤、緑、黄、アンバー、青、ピュアホワイト。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, 39.5, 512);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'AL2', 'Ø12 A2シリーズ 照光押ボタンスイッチ/表示灯', '明るく鮮明な照光面、快適な操作感触。モメンタリ形、オルタネイト形。保護構造: IP65 (照光押ボタンスイッチ), IP40 (表示灯) (IEC60529)', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 520);
