INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'LD6A形', 'LED積層表示灯', 'ユニバーサルデザインを採用し、視認性を追求した楕円形状、ストライプデザインのLED積層表示灯。ポール取付け、L形金具、直接機器への取付けなど5タイプの取付けパターンを選択可能。独自の接続形状により組替えが簡単で、プラグイン端子接続を採用。点灯、点滅、ブザーの3タイプがあり、国際規格(IEC規格)適合の点滅周期(1.75Hz)。3パターンの照光方法（拡散レンズ、集光レンズ、導光）で各方向からの高い視認性を実現。独自の共鳴設計で360°に拡がる大音量2パターンのブザー音(3.3kHz、最大90dB、音圧調節レバー付)を発生。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 538);
