INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'HE2B-M2', '3ポジションイネーブルスイッチ', '機械の予期しない動作時に危険を回避するための3ポジションイネーブルスイッチ。人間工学に配慮した3ポジション動作と、アクチュエータから接点までが2重化された高い安全レベルが特徴。操作荷重の変化が小さく、耐久性にも優れる。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 629);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'HS1L-DQ4', 'ソレノイド付安全スイッチ HS1L形', 'ロック強度3000N。大形で重い扉、強固なロック強度が必要な扉に最適。6接点内蔵で、ドアの開閉状態とロック状態をそれぞれモニタリング可能。安全性と使いやすさも向上し、手動ロック解除keyにより停電時やメンテナンス時に手動でロック解除が可能。表示灯は独立回路で自由な使用用途に利用可能。ソレノイドの励磁でロック解除するスプリングロックタイプと、ソレノイドの励磁でロックするソレノイドロックタイプの2種類のロック機構を用意。使用周囲温度-20~+55℃と広範囲で使用可能。UL, TUV, CE, UKCA認証取得。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 716);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'HR1S-AF5130B', '非接触安全スイッチ用安全リレーモジュール', 'HR1S-AF形、端子部固定タイプ。電源電圧: AC 24V -15~+10% 50/60Hz。保護構造: 端子部IP20、本体ケースIP40。対応パフォーマンスレベル e (EN ISO 13849-1)、安全性インテグリティレベル 3 (EN 62061)。販売中止 2021/10/29。', NULL, NULL, 'https://drive.google.com/drive/folders/', 22.5, 99, 114, 766);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'HR1S-AF5130PB', '非接触安全スイッチ用安全リレーモジュール', 'HR1S-AF形、端子部着脱タイプ。電源電圧: DC 24V -15~+10%。保護構造: 端子部IP20、本体ケースIP40。対応パフォーマンスレベル e (EN ISO 13849-1)、安全性インテグリティレベル 3 (EN 62061)。HR1S-AFシリーズは販売中止 2021/08/31。', NULL, NULL, 'https://drive.google.com/drive/folders/', 22.5, 99, 114, 766);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'HS3A形', '非接触安全スイッチ', '安全機能内蔵でPLe、カテゴリ4、SIL CL3に対応する非接触安全スイッチ。回路内部の異常を自動検出。RFID方式採用により、緩やかな動作やがたつきのある扉でも安定検出。予備アクチュエータによる無効化を防止するユニコードタイプ。金属切粉が付着しにくい衛生的構造で、磁石不使用のため耐環境性に優れる。本体設置は5方向に対応し、扉のタイプや向きを選ばない。LED表示により扉の異常や直列接続時の異常を個別判別可能。EN/ISO 13849-1 カテゴリ4 PLe、EN 62061 SIL3に適合。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 768);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'SE4D-H12D', 'セーフティライトカーテン SE4D形 受光器', '前面取付で施工性が大幅に向上。光軸調整用六角穴付ボルトは作業性のよい前面取付けです。ボルトが見やすく光軸調整が簡単、また光軸の調整部をM5のボルトでダイレクトにしっかり固定するため、光軸ズレが起きにくい構造になっています。投光器と受光器の区別がしやすく、形番も前面に表示。現場での使いやすさにこだわった多彩な機能を搭載。入光位置がひとめでわかる光軸合わせ調整機能。RS-485で最大4台を接続可能。4倍のエリアを監視! カテゴリ4 PLe SIL3。ULUS TUV LISTED CE 規格認証。販売中止 2023/6/30。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 790);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'SE4D-H12E', 'セーフティライトカーテン SE4D形 投光器', '前面取付で施工性が大幅に向上。光軸調整用六角穴付ボルトは作業性のよい前面取付けです。ボルトが見やすく光軸調整が簡単、また光軸の調整部をM5のボルトでダイレクトにしっかり固定するため、光軸ズレが起きにくい構造になっています。投光器と受光器の区別がしやすく、形番も前面に表示。現場での使いやすさにこだわった多彩な機能を搭載。入光位置がひとめでわかる光軸合わせ調整機能。RS-485で最大4台を接続可能。4倍のエリアを監視! カテゴリ4 PLe SIL3。ULUS TUV LISTED CE 規格認証。販売中止 2023/6/30。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 790);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'SE4D形', 'ミューティング制御機能搭載ライトカーテン', '人体の通過時のみラインを停止させ、ワークの通過時はライトカーテンを止めないミューティング制御機能を搭載。ミューティングセンサとミューティングランプをライトカーテン本体に直接接続することが可能で、ミューティング専用のコントローラは不要。オーバーライド機能搭載で、ライン停止時もスムーズかつ安全に再始動可能。応答速度14ms以下。光軸数や直列接続台数に関係なく高速応答14ms以下を実現し、安全距離の計算工数を軽減。最大3台または192光軸まで連結接続可能。1台でPNPトランジスタ出力とNPNトランジスタ出力に対応し、極性は配線で簡単切り換えが可能。販売中止 2023/6/30。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 791);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'SE4D形', 'セーフティライトカーテン', 'セーフティリレーモジュール不要で安全回路を構築。EDM(外部デバイスモニタ)機能内蔵。各種ブランキング機能対応。販売中止 2023/6/30。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, undefined);
