INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'SE4D', 'セーフティライトカーテン', '制御カテゴリ4対応のセーフティライトカーテン。投光器と受光器を複数台直列または並列に接続可能。直列接続では最大3セット、合計光軸数最大192光軸まで接続可能。並列接続では最大3セットまで接続可能。制御出力(OSSD1/2)は、遮光状態になったセットのみOFF。PNP出力で使用。販売中止 2023/6/30。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 801);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'SE9Z-CSL05', '直列接続用ケーブル', 'SE4D形セーフティライトカーテンの直列接続に使用する専用ケーブル。投光器と投光器、および受光器と受光器の接続に必要。誤接続は検出不能領域発生の原因となるため注意が必要。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 801);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'SE4D', 'セーフティライトカーテン', 'インタロック機能、投光停止機能、干渉防止機能、補助出力(非安全出力)を搭載したセーフティライトカーテン。手動リセット/自動リセットの選択が可能。投光動作の停止、複数台の干渉防止、非安全用途の補助出力に対応。販売中止 (2023/6/30)。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, undefined);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'SE9Z-HC', 'ハンディコントローラ', 'SE4D形セーフティライトカーテンの設定変更に使用する別売りのコントローラ。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, undefined);
