INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'HR2S-332N-T075', '安全リレーモジュール', 'EN ISO 13849-1パフォーマンスレベルe、カテゴリ4対応の安全リレーモジュール。スプリング端子着脱式端子台採用、コネクタカバー機構により接続不具合を発見。3NO(即断)+3NO(タイムディレー)の多接点出力で、31通りの設定時間から最適なタイムディレー時間を選択可能。テュフズード認証品。本製品(HR1S形/HR2S形)は販売中止となっており、代替機種はHR6S形です。詳細は仕様表を参照してください。', NULL, NULL, 'https://drive.google.com/drive/folders/', 45, NULL, NULL, 869);
