INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'HR1S-AF5130B', 'HR1S-AF形安全リレーモジュール', '固定タイプ。AC 24V -15~+10% 50/60Hz。起動スイッチの溶着検出が可能な小形高機能タイプ。モジュールの交換が容易に行える端子部着脱タイプもご用意。安全回路の2重化による故障診断機能を搭載。内蔵リレーの動作をLED表示でモニタ可能。フィンガープロテクト構造採用。35mm幅DINレール取付タイプ。EN(欧州規格)、IEC規格(国際規格)に適合。テュフノルトによる認証。UL、CSA認証品。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, undefined);
