INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'HR1S-AK311144', 'HR1S-AK形安全リレーモジュール (固定タイプ)', 'トランジスタ出力4点装備。固定タイプ。モジュールの交換が容易に行える端子部着脱タイプもご用意。ライトカーテンとの接続が可能。安全回路の2重化による故障診断機能を搭載。内蔵リレーの動作をLED表示でモニタ可能。フィンガープロテクト構造採用。35mm幅DINレール取付タイプ。EN(欧州規格)、IEC規格(国際規格)に適合。テュフノルトによる認証。UL、CSA認証品。定格電源電圧: AC 24V -15~+10% 50/60Hz / DC 24V -15~+10%。使用周囲温度: -10～+55℃(ただし、氷結しないこと)。保護構造: 端子部:IP20 本体ケース:IP40。販売中止。代替機種HR6S形については下記をご覧ください。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 884);
