INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'EX4R-D4形', '本質安全防爆構造 タッチスイッチ付表示器', '生産性や作業性を向上させる使いやすい機能が満載。水素ガスを含むゾーン1・ゾーン2の危険場所でタッチパネルを使用可能。明るい場所でも見やすい画面。SVGA・12.1インチ高輝度LCD搭載により、視認性に優れた画面で、最高クラスの表示性能を実現。LEDバックライトによる48段階の調光機能で最適な明るさに調整可能。EX4R-D44G形 (12.1インチ) 550 cd/m。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 899);
