INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'EC2B', '耐圧・安全増防爆構造 コントロールボックス EC2B形', 'ATEX指令(欧州防爆指令)適合。海外向けプラントに最適な耐食性ステンレス製ボックス。すべての爆発性ガス・蒸気(ゾーン1・2)および爆発性粉じん(ゾーン21・22)で使用可能。防爆性能: Ex de IIC T6 Gb (<PTB, TIIS>), Ex tD A21 IP65 T80℃ (<PTB>)。材質: ステンレス鋼板(SUS304)。規格認証: IECEx, cULus LISTED, CE, TIIS。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 900);
