INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'PSM-03', '無線ネットワークカメラ', '爆発性ガスが存在する石油化学プラント等の危険場所で使用可能。遠隔操作で光学ズーム32倍の定点監視が可能。有線/無線接続に対応し、PoE接続か無線LAN接続を選択可能。本体重量8kgで設置・運用が容易。監視場所の変更や設置場所の選択が自由。保護構造: IP65。設置場所: ゾーン1, ゾーン2。防爆性能: Ex d II B T4 +H2, Ex de II B T4 +H2。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 903);
