INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'RLシリーズ', 'パワーリレー', '30A(1極)の高容量パワーリレー。同極接点間3mm安全設計 (情報機器1次回路インターロック要求 (IEC60950-1)対応)。50%瞬低も動作継続 (瞬間的な電圧ドロップ (50%) でも安定して動作継続)。単相制御の電磁接触器の置換えに最適。取付方向に制限なし (リレーの仕様に影響がなく、自由に取付できます)。軽量で作業効率アップ (約1/3までの軽量化, 取付作業効率アップや装置のトータル軽量化に貢献)。電磁接触器に比べ、低騒音・低衝撃 (機器の静音化に貢献)。DINレール取付も簡単ラクラク (IDECオリジナル構造, ワンタッチでDINレールに取付)。小型化により、設置スペースを有効活用。オプションパーツ不要の為、部品点数・組立工数削減。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 972);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm, page_number) VALUES ((SELECT id FROM manufacturers WHERE name = 'IDEC' LIMIT 1), 'SU2S-11L', 'スプリングクランプ式リレーソケット SUシリーズ', 'スプリングクランプ式リレーソケット。配線工数50%削減、IP20フィンガープロテクト構造。35mm幅DINレール取付用。専用渡り金具でコイル側を簡単配線。高い安全性と信頼性（端子配列、スプリングクランプ式接続による高接触信頼性・耐振動性）。メンテナンス工数削減（緩みなし、トルク管理不要）。販売中止 2021/3/30。', NULL, NULL, 'https://drive.google.com/drive/folders/', NULL, NULL, NULL, 988);
